var getAdditionalData = async (option, categoriName) => {
  const filePath = `${MainPlugin.instance.dbPath}/${option}.json`;
  try {
    const file = await MainPlugin.instance.app.vault.adapter.read(filePath);
    if (categoriName === "income_plan" || categoriName === "expenditure_plan") {
      const jsonData = JSON.parse(file)[option][categoriName];
      const data = {
        jsonData,
        status: "success"
      };
      return data;
    } else if (option === "accounts") {
      const jsonData = JSON.parse(file)[option];
      const data = {
        jsonData,
        status: "success"
      };
      return data;
    } else {
      return { status: "error", error: new Error("Invalid option provided") };
    }
  } catch (error) {
    return { status: "error", error: error instanceof Error ? error : new Error(String(error)) };
  }
};
var getMainData = async (option) => {
  const { selectedYear, selectedMonth } = stateManager();
  const { year: year2, month } = selectedYear && selectedMonth ? { year: selectedYear, month: selectedMonth } : getDate();
  const filePath = `${MainPlugin.instance.dbPath}/${year2}.json`;
  try {
    const file = await MainPlugin.instance.app.vault.adapter.read(filePath);
    const jsonData = JSON.parse(file).months[month][option];
    const data = {
      jsonData,
      status: "success"
    };
    return data;
  } catch (error) {
    return { status: "error", error: error instanceof Error ? error : new Error(String(error)) };
  }
};
var getAllFile = async (option) => {
  const filePath = `${MainPlugin.instance.dbPath}/${option}.json`;
  try {
    const file = await MainPlugin.instance.app.vault.adapter.read(filePath);
    const jsonData = JSON.parse(file);
    return { status: "success", json: jsonData };
  } catch (error) {
    return { status: "error", error: error instanceof Error ? error : new Error(String(error)) };
  }
};
