function humanizeDate(dateStr) {
  const [year2, month, day] = dateStr.split("-").map(Number);
  const date = new Date(year2, month - 1, day);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const diffDays = Math.round(
    (today.getTime() - date.getTime()) / (1e3 * 60 * 60 * 24)
  );
  const weekdays = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday"
  ];
  const months = [
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December"
  ];
  let prefix = "";
  if (diffDays === 0)
    prefix = "Today";
  else if (diffDays === 1)
    prefix = "Yesterday";
  else if (diffDays === -1)
    prefix = "Tomorrow";
  else if (diffDays === 2)
    prefix = "The day before yesterday";
  else if (diffDays === -2)
    prefix = "The day after tomorrow";
  const currentYear = today.getFullYear();
  const showYear = date.getFullYear() !== currentYear;
  const formattedDate = showYear ? `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}, ${weekdays[date.getDay()]}` : `${months[date.getMonth()]} ${date.getDate()}, ${weekdays[date.getDay()]}`;
  return prefix ? `${prefix}, ${formattedDate}` : formattedDate;
}
