var expenditureTransaction = async (data, modifier, oldData) => {
  const amount = new big_default(data.amount);
  const billsRes = await getAllFile("accounts");
  if (billsRes.status === "error")
    return { status: "error", error: billsRes.error };
  const { selectedYear, selectedMonth } = stateManager();
  const { year: year2, month } = selectedYear && selectedMonth ? { year: selectedYear, month: selectedMonth } : getDate();
  const plansRes = await getAllFile(year2);
  if (plansRes.status === "error")
    return { status: "error", error: plansRes.error };
  let bills = billsRes.json.accounts;
  let plans = plansRes.json.months[month].expenditure_plan;
  const update = async () => {
    billsRes.json.accounts = bills;
    plansRes.json.months[month].expenditure_plan = plans;
    const billUpdate = await updateFile("accounts", billsRes.json);
    if (billUpdate.status === "error")
      return { status: "error", error: billUpdate.error };
    const planUpdate = await updateFile(`${year2}`, plansRes.json);
    if (planUpdate.status === "error")
      return { status: "error", error: planUpdate.error };
    return { status: "success" };
  };
  const updateBill = (billId, delta) => {
    bills = bills.map(
      (b) => b.id === billId ? { ...b, balance: new big_default(b.balance).plus(delta).toFixed(2) } : b
    );
  };
  const updatePlan = (planId, delta) => {
    plans = plans.map(
      (p) => p.id === planId ? { ...p, amount: new big_default(p.amount).plus(delta).toFixed(2) } : p
    );
  };
  const caseEdit = async () => {
    if (!oldData)
      return { status: "error", error: new Error("Old data is required for edit") };
    const oldAmount = new big_default(oldData.amount);
    updateBill(oldData.bill.id, oldAmount);
    updatePlan(oldData.category.id, oldAmount.times(-1));
    await update();
    const newBillsRes = await getAllFile("accounts");
    const newPlansRes = await getAllFile(year2);
    if (newBillsRes.status === "error")
      return { status: "error", error: newBillsRes.error };
    if (newPlansRes.status === "error")
      return { status: "error", error: newPlansRes.error };
    bills = newBillsRes.json.accounts;
    plans = newPlansRes.json.months[month].expenditure_plan;
    updateBill(data.bill.id, amount.times(-1));
    updatePlan(data.category.id, amount);
    return await update();
  };
  switch (modifier) {
    case "add":
      updateBill(data.bill.id, amount.times(-1));
      updatePlan(data.category.id, amount);
      return await update();
    case "remove":
      updateBill(data.bill.id, amount);
      updatePlan(data.category.id, amount.times(-1));
      return await update();
    case "edit":
      return await caseEdit();
    default:
      return { status: "error", error: new Error("Invalid modifier") };
  }
};
