async function handleSearchInput(e, historyContent, mainContentBody) {
  const target = e.target;
  const searchValue = target.value;
  const result = await searchHistory(searchValue);
  if (result.status === "error") {
    new import_obsidian4.Notice(result.error.message);
    console.error(result.error);
    return;
  }
  historyContent.empty();
  if (!result.jsonData.length) {
    const undefinedContent = historyContent.createEl("div", {
      cls: "undefined-content"
    });
    historyContent.addClass("main-content-body--undefined");
    undefinedContent.createEl("span", { text: "\u{1F355} \u{1F3AE} \u{1F455}" });
    undefinedContent.createEl("p", { text: "No matching operations found." });
  } else if (result.jsonData.length >= 1) {
    historyContent.removeClass("main-content-body--undefined");
    void generationHistoryContent(historyContent, result, mainContentBody);
  } else {
    historyContent.removeClass("main-content-body--undefined");
    void generationHistoryContent(historyContent, result, mainContentBody);
  }
}
async function generationHistoryContent(historyContent, historyData, mainContentBody, mainContentButton) {
  mainContentBody == null ? void 0 : mainContentBody.removeClass("main-content-body--padding");
  if (historyData.status === "error")
    return historyData.error;
  if (historyData.jsonData.length) {
    const now = new Date().getTime();
    const groupedByDay = Object.values(
      historyData.jsonData.reduce(
        (acc, item) => {
          const day = item.date.split("T")[0];
          if (!acc[day]) {
            acc[day] = [];
          }
          acc[day].push(item);
          return acc;
        },
        {}
      )
    ).map((group) => group.flat()).sort(
      (a, b) => new Date(b[0].date).getTime() - new Date(a[0].date).getTime()
    );
    const result = groupedByDay.map(
      (dayGroup) => dayGroup.sort(
        (a, b) => Math.abs(new Date(a.date).getTime() - now) - Math.abs(new Date(b.date).getTime() - now)
      )
    );
    if (historyData.jsonData.length >= 5) {
      mainContentBody == null ? void 0 : mainContentBody.addClass("main-content-body--padding");
    }
    for (const historyElement of result) {
      const historyBlock = historyContent.createEl("div", {
        cls: "history-block"
      });
      const headerBlock = historyBlock.createEl("div", {
        cls: "header-block"
      });
      const dateBlock = headerBlock.createEl("div", {
        cls: "header-date-block"
      });
      dateBlock.createEl("p", {
        text: humanizeDate(historyElement[0].date.split("T")[0])
      });
      const amountBlock = headerBlock.createEl("div", {
        cls: "header-amount-block"
      });
      amountBlock.createEl("span", {
        text: `${SummarizingDataForTheDay(historyElement)}`
      });
      const dataList = historyBlock.createEl("ul", {
        cls: "data-list"
      });
      for (const element of historyElement) {
        const dataItem = dataList.createEl("li", {
          cls: "data-item",
          attr: {
            "data-id": element.id
          }
        });
        dataItem.onclick = (e) => {
          void editingHistory(e);
        };
        const searchCategory = await searchElementById(element.category.id, element.type);
        if (searchCategory.status === "error")
          return new import_obsidian4.Notice(searchCategory.error.message);
        const searchBill = await searchElementById(element.bill.id, "accounts");
        if (searchBill.status === "error")
          return new import_obsidian4.Notice(searchBill.error.message);
        const dataText = dataItem.createEl("div", {
          cls: "data-link"
        });
        const divEmoji = dataText.createEl("div", {
          cls: "data-link-emoji"
        });
        const divText = dataText.createEl("div", {
          cls: "data-link-text"
        });
        divEmoji.createEl("p", {
          text: `${searchCategory.item.emoji}`
        });
        divEmoji.createEl("span", {
          text: `${searchBill.item.emoji}`
        });
        if (element.comment === "") {
          divText.createEl("p", {
            text: `${searchCategory.item.name}`
          });
          divText.createEl("span", {
            text: `${searchBill.item.name}`
          });
        } else {
          divText.createEl("p", {
            text: `${element.comment}`
          });
          divText.createEl("span", {
            text: `${searchBill.item.name} \u2022 ${searchCategory.item.name}`
          });
        }
        const dataAmount = dataItem.createEl("div", {
          cls: "data-link"
        });
        dataAmount.createEl("p", {
          text: `${checkExpenceOrIncome(element.amount, element.type)} ${getCurrencySymbol(searchBill.item.currency)}`
        });
      }
    }
  }
  const addHistoryButton2 = mainContentButton == null ? void 0 : mainContentButton.createEl("button", {
    text: "Add an expense or income",
    cls: "add-button"
  });
  addHistoryButton2 == null ? void 0 : addHistoryButton2.addEventListener("click", () => {
    void addHistory();
  });
}
